      algorithm: ["totalSum","minWindowSum","slide","remove","add","windowSize","answer"],
      tradeoff: ["prefix sums","split point","reconstruct","O(n)","cleaner","window","same"],
      complexity: ["O(n)","time","O(1)","space","three scalars","dominates","k≤n"],
